import React from 'react';
import ReactDOM from 'react-dom/client';
import "./styles.css"; // Your CSS file
import App from './App';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')  // This should match the <div id="root"></div> in index.html
);
